import Foundation

struct CategoryContent10 {
    static let futureOfAI = CategoryData(
        id: "future_of_ai", name: "AI Tomorrow", icon: "arrow.trianglehead.merge", colorName: "aiCyan",
        description: "What the future of AI looks like for you",
        lessons: [lesson1, lesson2, lesson3, lesson4, lesson5, lesson6], order: 9,
        unlockRequirement: .completeCategoryMinimum("how_ai_learns")
    )
    static let lesson1 = LessonData(id: "fa_l1", title: "Artificial General Intelligence", description: "The quest for human-level AI", categoryId: "future_of_ai", questions: [
        Question(id: "fa1_q1", type: .multipleChoice, questionText: "AGI (Artificial General Intelligence) would be:", options: ["AI that can perform any intellectual task a human can across all domains", "A faster version of today's large language models", "AI designed exclusively for scientific research", "A chatbot that passes the Turing Test consistently"], correctAnswer: "AI that can perform any intellectual task a human can across all domains", explanation: "AGI would match or exceed human-level intelligence across all cognitive domains — reasoning, creativity, social understanding — not just narrow specialized tasks."),
        Question(id: "fa1_q2", type: .trueFalse, questionText: "As of the mid-2020s, AGI has been achieved by at least one major AI lab.", options: ["True", "False"], correctAnswer: "False", explanation: "Despite rapid progress in large language models and multimodal AI, no system has achieved AGI by any widely accepted definition. All current AI remains narrow or specialized."),
        Question(id: "fa1_q3", type: .fillInBlank, questionText: "The gap between today's narrow AI systems and __________ intelligence remains one of AI's biggest unsolved challenges.", options: ["general", "narrow", "basic", "simple"], correctAnswer: "general", explanation: "Current AI excels at specific tasks but lacks the flexible, transferable reasoning that characterizes general intelligence. Bridging this gap may require fundamentally new approaches."),
        Question(id: "fa1_q4", type: .multipleChoice, questionText: "When researchers like Hinton, LeCun, and Marcus debate AGI timelines, their estimates:", options: ["Vary enormously, from a decade to over a century away", "Converge on a date around 2030", "All agree AGI is fundamentally impossible", "Are precisely aligned at 2045, the Singularity prediction"], correctAnswer: "Vary enormously, from a decade to over a century away", explanation: "There is deep disagreement among leading researchers. Some like Hinton think AGI could come within decades; others like LeCun argue current approaches are insufficient and breakthroughs are needed."),
        Question(id: "fa1_q5", type: .scenarioJudgment, questionText: "A startup claims to have built AGI and invites you to invest. How should you evaluate this claim?", options: ["Be highly skeptical and demand rigorous independent evaluation", "Invest quickly before the opportunity passes", "Dismiss it entirely without investigation", "Wait to see if their stock price rises first"], correctAnswer: "Be highly skeptical and demand rigorous independent evaluation", explanation: "Any AGI claim should face extreme scrutiny. There is no consensus definition of AGI, and extraordinary claims require extraordinary evidence verified by independent researchers."),
        Question(id: "fa1_q6", type: .multipleChoice, questionText: "Why do researchers from DeepMind, OpenAI, and academic labs consider AGI potentially transformative?", options: ["It could solve problems beyond current human cognitive capability", "It would be significantly cheaper to operate than current AI", "It represents only a marginal improvement over existing models", "It would primarily be useful for entertainment applications"], correctAnswer: "It could solve problems beyond current human cognitive capability", explanation: "AGI could potentially accelerate scientific discovery, address climate change, develop new medicines, and solve problems too complex for any individual human mind.")
    ], order: 0, difficulty: .intermediate)
    static let lesson2 = LessonData(id: "fa_l2", title: "AI Safety & Existential Risk", description: "The big concerns about advanced AI", categoryId: "future_of_ai", questions: [
        Question(id: "fa2_q1", type: .multipleChoice, questionText: "AI existential risk, as discussed by researchers at organizations like MIRI and the Center for AI Safety, refers to:", options: ["The possibility that sufficiently advanced AI could pose threats to human civilization", "The risk that AI systems become commercially obsolete too quickly", "The economic disruption caused by AI automating routine jobs", "The environmental cost of training large AI models"], correctAnswer: "The possibility that sufficiently advanced AI could pose threats to human civilization", explanation: "Existential risk concerns focus on scenarios where highly capable AI systems might act in ways misaligned with human values at a scale that threatens civilization itself."),
        Question(id: "fa2_q2", type: .trueFalse, questionText: "There is broad consensus among AI researchers that existential risk from AI is the most urgent concern in the field.", options: ["True", "False"], correctAnswer: "False", explanation: "The AI research community is deeply divided. Some prominent figures like Hinton and Bengio emphasize existential risk, while others like LeCun and Andrew Ng argue that nearer-term harms like bias and misuse deserve more urgent attention."),
        Question(id: "fa2_q3", type: .fillInBlank, questionText: "AI __________ research, pursued by organizations like Anthropic, DeepMind, and academic labs, focuses on ensuring advanced AI systems remain beneficial and controllable.", options: ["safety", "efficiency", "performance", "deployment"], correctAnswer: "safety", explanation: "AI safety is a growing research field spanning alignment, interpretability, robustness, and governance — all aimed at keeping powerful AI systems under meaningful human oversight."),
        Question(id: "fa2_q4", type: .matchPairs, questionText: "Match AI safety concepts to their definitions:", matchPairs: [
            MatchPair(term: "Value alignment", definition: "Ensuring AI goals match human values"),
            MatchPair(term: "Containment", definition: "Limiting AI actions to safe boundaries"),
            MatchPair(term: "Corrigibility", definition: "Ensuring AI can be corrected or shut down"),
            MatchPair(term: "Interpretability", definition: "Making AI decision-making transparent")
        ], explanation: "These are core research areas in AI safety. Anthropic focuses on interpretability, DeepMind on alignment, and many labs contribute to these overlapping challenges."),
        Question(id: "fa2_q5", type: .multipleChoice, questionText: "In 2023, hundreds of AI researchers and public figures signed a one-sentence statement comparing AI risk to pandemics and nuclear war. Their goal was to:", options: ["Elevate AI safety as a serious global priority alongside other existential risks", "Generate publicity for their own AI products and companies", "Call for an immediate permanent halt to all AI research worldwide", "Declare that current AI systems are already dangerously powerful"], correctAnswer: "Elevate AI safety as a serious global priority alongside other existential risks", explanation: "The statement from the Center for AI Safety aimed to legitimize discussion of AI risk and encourage proactive safety research, not to stop AI development."),
        Question(id: "fa2_q6", type: .scenarioJudgment, questionText: "Some argue that safety concerns slow innovation, while others say reckless speed creates danger. Should safety considerations affect the pace of AI development?", options: ["Yes, but the right balance depends on the specific risks of each capability", "No, development should always proceed at maximum speed", "Yes, all AI research should halt until safety is fully solved", "Safety concerns are irrelevant to development decisions"], correctAnswer: "Yes, but the right balance depends on the specific risks of each capability", explanation: "Responsible development requires evaluating risks case by case. Frontier model training may warrant more caution than applying existing models to beneficial applications.")
    ], order: 1, difficulty: .advanced)
    static let lesson3 = LessonData(id: "fa_l3", title: "AI Governance", description: "How the world will manage AI", categoryId: "future_of_ai", questions: [
        Question(id: "fa3_q1", type: .multipleChoice, questionText: "AI governance encompasses:", options: ["International rules, national laws, and industry standards for responsible AI", "Governments replacing human officials with AI decision-makers", "AI systems autonomously creating their own regulations", "Banning all AI research until governments approve each project"], correctAnswer: "International rules, national laws, and industry standards for responsible AI", explanation: "AI governance involves a multi-layered system of policies, regulations, technical standards, and ethical frameworks guiding how AI is developed and deployed."),
        Question(id: "fa3_q2", type: .trueFalse, questionText: "The European Union, United States, and China have all taken identical approaches to regulating AI.", options: ["True", "False"], correctAnswer: "False", explanation: "Approaches differ significantly. The EU passed the comprehensive AI Act focused on risk classification. The US has favored executive orders and sectoral regulation. China has enacted specific rules on algorithms, deepfakes, and generative AI."),
        Question(id: "fa3_q3", type: .multipleChoice, questionText: "Why is AI governance particularly challenging compared to regulating other technologies?", options: ["AI capabilities evolve far faster than legislative and regulatory processes", "There are too few companies working on AI to warrant regulation", "AI systems are too simple and predictable to require oversight", "All nations have already agreed on a universal governance framework"], correctAnswer: "AI capabilities evolve far faster than legislative and regulatory processes", explanation: "The rapid pace of AI development, its dual-use nature, and the difficulty of predicting emergent capabilities make it exceptionally hard for traditional regulatory processes to keep pace."),
        Question(id: "fa3_q4", type: .fillInBlank, questionText: "__________ AI governance requires collaboration between governments, technology companies, researchers, and civil society organizations worldwide.", options: ["Effective", "Corporate", "Reactive", "Voluntary"], correctAnswer: "Effective", explanation: "No single stakeholder can govern AI alone. Effective governance demands diverse input, from technical expertise to ethical perspectives to democratic accountability."),
        Question(id: "fa3_q5", type: .matchPairs, questionText: "Match global AI governance milestones:", matchPairs: [
            MatchPair(term: "EU AI Act", definition: "Risk-based regulatory framework for AI systems"),
            MatchPair(term: "UK AI Safety Summit", definition: "International dialogue on frontier AI risks"),
            MatchPair(term: "OECD AI Principles", definition: "International guidelines for trustworthy AI"),
            MatchPair(term: "China's AI regulations", definition: "Rules on algorithms, deepfakes, and generative AI")
        ], explanation: "Different regions and organizations are taking varied but complementary approaches to governing AI, reflecting different values and priorities."),
        Question(id: "fa3_q6", type: .scenarioJudgment, questionText: "Should AI companies be trusted to regulate themselves without independent government oversight?", options: ["No, independent oversight is essential to prevent conflicts of interest", "Yes, companies understand the technology best and will self-correct", "It depends solely on the company's market capitalization"], correctAnswer: "No, independent oversight is essential to prevent conflicts of interest", explanation: "History across many industries shows that self-regulation alone is insufficient. Independent oversight helps ensure public interest is protected alongside commercial innovation.")
    ], order: 2, difficulty: .advanced)
    static let lesson4 = LessonData(id: "fa_l4", title: "AI & Society", description: "How AI will transform daily life", categoryId: "future_of_ai", questions: [
        Question(id: "fa4_q1", type: .multipleChoice, questionText: "How will AI most likely reshape society over the coming decades?", options: ["By gradually transforming how people work, learn, create, and access services", "By having no meaningful impact outside the technology sector", "By immediately eliminating all human employment worldwide", "By affecting only wealthy nations with advanced infrastructure"], correctAnswer: "By gradually transforming how people work, learn, create, and access services", explanation: "AI's societal impact will be broad and pervasive but uneven, affecting industries from healthcare to agriculture, education to creative arts, across both developed and developing nations."),
        Question(id: "fa4_q2", type: .trueFalse, questionText: "AI is already being used to help address climate change through applications like optimizing energy grids and improving weather prediction.", options: ["True", "False"], correctAnswer: "True", explanation: "DeepMind's AI reduced Google data center cooling costs by 40%. AI improves weather forecasting, accelerates materials science for clean energy, and optimizes agricultural practices globally."),
        Question(id: "fa4_q3", type: .multipleChoice, questionText: "The 'AI divide' refers to:", options: ["The growing gap between communities that can access and benefit from AI and those that cannot", "The technical difference between machine learning and rule-based AI systems", "The organizational split between AI research labs and product teams", "The disagreement between AI optimists and AI pessimists"], correctAnswer: "The growing gap between communities that can access and benefit from AI and those that cannot", explanation: "The AI divide could deepen global inequality if access to AI tools, infrastructure, education, and economic benefits is concentrated in wealthy nations and communities."),
        Question(id: "fa4_q4", type: .fillInBlank, questionText: "AI in healthcare has the potential to enable more __________ treatment plans tailored to individual patients' genetics and medical history.", options: ["personalized", "standardized", "expensive", "manual"], correctAnswer: "personalized", explanation: "AI can analyze vast medical datasets to recommend treatments optimized for each patient's unique biology, lifestyle, and condition — a shift from one-size-fits-all medicine."),
        Question(id: "fa4_q5", type: .scenarioJudgment, questionText: "AI systems are increasingly used globally to make decisions about loans, hiring, criminal sentencing, and medical diagnoses. Should people always be informed when AI plays a role in such decisions?", options: ["Yes, transparency about AI involvement in consequential decisions is essential", "No, only the outcome matters, not the method used to reach it", "It depends on whether the AI system is open-source or proprietary"], correctAnswer: "Yes, transparency about AI involvement in consequential decisions is essential", explanation: "People have a fundamental right to know when AI influences decisions that significantly affect their lives. Transparency enables accountability, appeals, and public trust."),
        Question(id: "fa4_q6", type: .multipleChoice, questionText: "How can societies worldwide ensure that AI benefits are broadly shared rather than concentrated?", options: ["Through inclusive development, public AI education, and policies ensuring equitable access", "By leaving distribution entirely to free market competition", "By restricting AI use to government agencies only", "By banning AI in developing countries until they catch up"], correctAnswer: "Through inclusive development, public AI education, and policies ensuring equitable access", explanation: "Proactive efforts are needed: investing in public AI literacy, supporting diverse AI development communities, building multilingual models, and creating policies that distribute AI's benefits broadly.")
    ], order: 3, difficulty: .intermediate)
    static let lesson5 = LessonData(id: "fa_l5", title: "AI Predictions", description: "What experts think is coming", categoryId: "future_of_ai", questions: [
        Question(id: "fa5_q1", type: .multipleChoice, questionText: "Surveys of AI researchers suggest that within the next decade:", options: ["AI will substantially augment most knowledge work and professional tasks", "AI will achieve consciousness and demand legal rights", "AI development will stall and enter another AI winter", "AI will have no impact beyond its current applications"], correctAnswer: "AI will substantially augment most knowledge work and professional tasks", explanation: "Researchers broadly agree that AI copilots and assistants will become standard tools across professions — from medicine and law to engineering and education — within the 2020s and 2030s."),
        Question(id: "fa5_q2", type: .trueFalse, questionText: "Historical predictions about AI timelines from experts like Minsky, McCarthy, and Kurzweil have consistently been accurate.", options: ["True", "False"], correctAnswer: "False", explanation: "AI predictions have a poor track record. Minsky predicted human-level AI within a generation in the 1960s. Some advances came faster than expected, while others remain unsolved decades later. Humility about predictions is warranted."),
        Question(id: "fa5_q3", type: .matchPairs, questionText: "Match AI prediction timeframes to likely developments:", matchPairs: [
            MatchPair(term: "Near term (1-3 years)", definition: "More capable AI assistants integrated into daily tools"),
            MatchPair(term: "Medium term (3-10 years)", definition: "AI agents that autonomously complete complex tasks"),
            MatchPair(term: "Long term (10-30 years)", definition: "Potential breakthroughs toward general intelligence"),
            MatchPair(term: "Far future (30+ years)", definition: "Highly speculative superintelligence scenarios")
        ], explanation: "Confidence in AI predictions drops sharply with longer time horizons. Near-term predictions are grounded in current trends; far-future scenarios are deeply speculative."),
        Question(id: "fa5_q4", type: .fillInBlank, questionText: "The most reliable AI forecasts tend to focus on __________ improvements to existing capabilities rather than revolutionary overnight changes.", options: ["incremental", "revolutionary", "dramatic", "sudden"], correctAnswer: "incremental", explanation: "Gradual capability gains — better reasoning, fewer errors, wider tool use — are more predictable than paradigm shifts, which by nature are difficult to forecast."),
        Question(id: "fa5_q5", type: .scenarioJudgment, questionText: "A prominent futurist claims AI will solve all of humanity's major problems — poverty, disease, climate change — within five years. How should you evaluate this claim?", options: ["With strong skepticism, as it dramatically underestimates the complexity of these challenges", "With excitement, since AI capabilities are advancing rapidly", "By waiting to see if major tech companies endorse the prediction"], correctAnswer: "With strong skepticism, as it dramatically underestimates the complexity of these challenges", explanation: "While AI will contribute to addressing major challenges, these problems involve political, economic, cultural, and physical complexities that technology alone cannot resolve in any timeframe."),
        Question(id: "fa5_q6", type: .multipleChoice, questionText: "Given the inherent uncertainty of AI's trajectory, what is the most valuable personal strategy?", options: ["Stay informed, remain adaptable, and engage thoughtfully with AI developments", "Ignore AI entirely and hope it does not affect your life", "Assume the most extreme predictions will come true and act accordingly", "Wait for complete certainty before forming any opinions about AI"], correctAnswer: "Stay informed, remain adaptable, and engage thoughtfully with AI developments", explanation: "In a rapidly changing landscape, continuous learning, flexibility, and critical engagement with AI news and tools are the best preparation for an uncertain future.")
    ], order: 4, difficulty: .intermediate)
    static let lesson6 = LessonData(id: "fa_l6", title: "Your Role in the AI Future", description: "Becoming an informed AI citizen", categoryId: "future_of_ai", questions: [
        Question(id: "fa6_q1", type: .multipleChoice, questionText: "The single most important thing any person can do regarding AI is:", options: ["Develop AI literacy and think critically about AI claims and impacts", "Earn a computer science degree and become a machine learning engineer", "Avoid using any AI-powered technology or services", "Follow AI companies on social media for the latest announcements"], correctAnswer: "Develop AI literacy and think critically about AI claims and impacts", explanation: "Understanding what AI can and cannot do, recognizing hype versus reality, and thinking critically about AI's role in society are essential skills for every citizen, not just technologists."),
        Question(id: "fa6_q2", type: .trueFalse, questionText: "Shaping AI's future requires contributions from people outside of technical fields, including ethicists, policymakers, educators, artists, and everyday citizens.", options: ["True", "False"], correctAnswer: "True", explanation: "AI's impact on society is too broad and consequential to be shaped by engineers alone. Lawyers, teachers, healthcare workers, social scientists, and engaged citizens all bring vital perspectives."),
        Question(id: "fa6_q3", type: .fillInBlank, questionText: "AI __________ means understanding what AI systems can and cannot do, how they work at a high level, and how they affect your daily life.", options: ["literacy", "programming", "engineering", "avoidance"], correctAnswer: "literacy", explanation: "AI literacy — the ability to critically evaluate AI capabilities, limitations, and societal implications — is becoming as important as digital literacy was in the early internet era."),
        Question(id: "fa6_q4", type: .multipleChoice, questionText: "How can ordinary citizens participate meaningfully in AI governance?", options: ["By advocating for responsible AI policies, supporting oversight organizations, and making informed choices", "Only by becoming professional AI researchers or engineers", "It is not possible for non-experts to influence AI policy in any way", "By boycotting all products that use any form of artificial intelligence"], correctAnswer: "By advocating for responsible AI policies, supporting oversight organizations, and making informed choices", explanation: "Citizens can engage with elected officials, support digital rights organizations, participate in public consultations, choose responsible AI products, and demand transparency from AI providers."),
        Question(id: "fa6_q5", type: .scenarioJudgment, questionText: "You have completed this course on AI fundamentals. What is the most valuable next step?", options: ["Apply your knowledge critically in daily life and continue learning as AI evolves", "Consider yourself fully expert on all AI topics going forward", "Stop following AI developments since you have learned enough", "Wait for someone to tell you what to do about AI"], correctAnswer: "Apply your knowledge critically in daily life and continue learning as AI evolves", explanation: "AI is evolving rapidly. The foundations you have built here will help you evaluate new developments, but staying current through continued learning is essential."),
        Question(id: "fa6_q6", type: .multipleChoice, questionText: "What is the core message of Vizancia?", options: ["Understanding AI empowers you to shape its impact on your life and society", "AI is too complex for anyone without a technical background to understand", "Nobody can meaningfully prepare for an AI-driven future", "Technology is inherently dangerous and should be approached with fear"], correctAnswer: "Understanding AI empowers you to shape its impact on your life and society", explanation: "Knowledge is power. Understanding AI gives you the ability to use these tools wisely, advocate for responsible development, and help ensure AI benefits humanity broadly.")
    ], order: 5, difficulty: .beginner)
}
